'use client';

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Product } from './types';

export interface CartItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
  stock_quantity: number;
  wholesaler_name?: string;
}

interface CartContextType {
  cart: CartItem[];
  addToCart: (product: Product, quantity?: number) => void;
  removeFromCart: (productId: string) => void;
  updateQuantity: (productId: string, quantity: number) => void;
  clearCart: () => void;
  totalItems: number;
  totalCost: number;
  isCartOpen: boolean;
  setIsCartOpen: (open: boolean) => void;
}

const CartContext = createContext<CartContextType | undefined>(undefined);

export const CartProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  useEffect(() => {
    const stored = localStorage.getItem('stokiloo_cart');
    if (stored) {
      try {
        setCart(JSON.parse(stored));
      } catch {
        setCart([]);
      }
    }
  }, []);

  const saveCart = (newCart: CartItem[]) => {
    setCart(newCart);
    localStorage.setItem('stokiloo_cart', JSON.stringify(newCart));
  };

  const addToCart = (product: Product, quantity = 1) => {
    const existing = cart.find((item) => item.productId === product.id);
    let newCart: CartItem[];

    if (existing) {
      const targetQty = existing.quantity + quantity;
      const finalQty = Math.min(targetQty, product.stock_quantity);
      newCart = cart.map((item) =>
        item.productId === product.id
          ? { ...item, quantity: finalQty }
          : item
      );
    } else {
      newCart = [
        ...cart,
        {
          productId: product.id,
          name: product.name,
          price: product.wholesale_price,
          quantity: Math.min(quantity, product.stock_quantity),
          stock_quantity: product.stock_quantity,
          wholesaler_name: product.wholesaler_name,
        },
      ];
    }
    saveCart(newCart);
  };

  const removeFromCart = (productId: string) => {
    const newCart = cart.filter((item) => item.productId !== productId);
    saveCart(newCart);
  };

  const updateQuantity = (productId: string, quantity: number) => {
    if (quantity <= 0) {
      removeFromCart(productId);
      return;
    }
    const item = cart.find((i) => i.productId === productId);
    if (!item) return;

    const finalQty = Math.min(quantity, item.stock_quantity);
    const newCart = cart.map((i) =>
      i.productId === productId ? { ...i, quantity: finalQty } : i
    );
    saveCart(newCart);
  };

  const clearCart = () => {
    saveCart([]);
  };

  const totalItems = cart.reduce((acc, item) => acc + item.quantity, 0);
  const totalCost = Number(cart.reduce((acc, item) => acc + item.price * item.quantity, 0).toFixed(2));

  return (
    <CartContext.Provider
      value={{
        cart,
        addToCart,
        removeFromCart,
        updateQuantity,
        clearCart,
        totalItems,
        totalCost,
        isCartOpen,
        setIsCartOpen,
      }}
    >
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (context === undefined) {
    throw new Error('useCart must be used within a CartProvider');
  }
  return context;
};
